<template>
  <el-form
    ref="form"
    label-width="200px"
  >
    <el-tabs type="border-card">
      <el-tab-pane label="導購分潤設置">
        <el-form-item label="是否開啟分潤">
          <el-switch
            v-model="form.distributor.show"
            active-color="#13ce66"
            inactive-color="#ff4949"
            active-value="1"
            inactive-value="0"
          />
        </el-form-item>
        <el-form-item label="拉新店鋪">
          <el-input
            v-model="form.distributor.distributor"
            class="input-m"
          >
            <i slot="suffix">%</i>
          </el-input>
          <span class="frm-tips">
            <i class="el-icon-warning-outline" /> 注：無拉新門店訊息，則不作分潤計算。
          </span>
        </el-form-item>
        <el-form-item label="拉新導購">
          <el-input
            v-model="form.distributor.seller"
            class="input-m"
          >
            <i slot="suffix">%</i>
          </el-input>
          <span class="frm-tips">
            <i class="el-icon-warning-outline" /> 注：無拉新導購訊息，則不作分潤計算。
          </span>
        </el-form-item>
        <el-form-item label="推廣導購">
          <el-input
            v-model="form.distributor.popularize_seller"
            class="input-m"
          >
            <i slot="suffix">%</i>
          </el-input>
          <span class="frm-tips">
            <i class="el-icon-warning-outline" /> 注：無推廣導購訊息，則不作分潤計算。
          </span>
        </el-form-item>
        <el-form-item label="門店開單">
          <el-input
            v-model="form.distributor.distributor_seller"
            class="input-m"
          >
            <i slot="suffix">%</i>
          </el-input>
          <span class="frm-tips">
            <i class="el-icon-warning-outline" /> 注：無門店開單導購訊息，則不作分潤計算。
          </span>
        </el-form-item>
        <el-form-item label="結算時間">
          訂單售後完成<el-input
            v-model="form.distributor.plan_limit_time"
            class="input-m"
            style="width: 100px"
          />天後結算
          <span
            class="frm-tips"
          ><i class="el-icon-warning-outline" /> 注：分潤時間從售後完成n天計算。</span>
        </el-form-item>
        <div class="section-footer with-border content-center">
          <el-button
            type="primary"
            @click="onSubmit"
          >
            儲存
          </el-button>
        </div>
      </el-tab-pane>
    </el-tabs>
  </el-form>
</template>
<script>
import { getDistributionConfig, setDistributionConfig } from '@/api/shop'

export default {
  data () {
    return {
      form: {
        distributor: {
          show: 0,
          distributor: 0,
          seller: 0,
          popularize_seller: 0,
          plan_limit_time: 0
        }
      }
    }
  },
  mounted () {
    this.getConfig()
  },
  methods: {
    getConfig () {
      getDistributionConfig().then((response) => {
        this.form = response.data.data
      })
    },
    onSubmit () {
      setDistributionConfig(this.form).then((response) => {
        this.form = response.data.data
        this.$message({
          type: 'success',
          message: '儲存成功'
        })
      })
    }
  }
}
</script>
<style scoped lang="scss"></style>
